def cache_get_json(key):
    try:
        value = memcache.get(key)
        if value is None:
            return None
        if isinstance(value, bytes):
            value = value.decode("utf-8")
        return json.loads(value)
    except Exception:
        return None


def cache_set_json(key, value, ttl):
    try:
        memcache.set(key, json.dumps(value), expire=ttl)
    except Exception:
        pass


def cache_delete(key):
    try:
        memcache.delete(key)
    except Exception:
        pass


def make_cache_key(prefix, *parts, **kwargs):
    payload = {
        "parts": parts,
        "kwargs": kwargs,
    }
    raw = f"{prefix}:{json.dumps(payload, sort_keys=True, separators=(',', ':'))}"
    digest = hashlib.sha256(raw.encode("utf-8")).hexdigest()
    return f"{prefix}:{digest}"


def cached_db_query(key, ttl, query_func):
    cached = cache_get_json(key)
    if cached is not None:
        return cached, True
    result = query_func()
    if result is not None:
        cache_set_json(key, result, ttl)
    return result, False


def cached_api_response(key, ttl, producer_func):
    cached = cache_get_json(key)
    if cached is not None:
        return cached, True
    result = producer_func()
    cache_set_json(key, result, ttl)
    return result, False


@app.route("/health", methods=["GET"])
def health():
    status = {"app": "ok", "memcached": "unknown"}
    try:
        memcache.set("healthcheck", "ok", expire=5)
        status["memcached"] = "ok" if memcache.get("healthcheck") else "down"
    except Exception:
        status["memcached"] = "down"
    return jsonify(status)


